#include <stdio.h>

int main() {
	long int x,y;
	scanf("%ld %ld",&x,&y);
	if(x==y)
	    printf("=");
	else if((x==2)&&(y==3))
	    printf("<");
	else if((x==3)&&(y==2))
	    printf(">");
	else if((x==2)&&(y==4))
	    printf("=");
	else if((x==4)&&(y==2))
	    printf("=");
	else if(x==1)
	    printf("<");
	else if(y==1)
	    printf(">");
	else if(x<y)
	    printf(">");
	else
	    printf("<");
	return 0;
}

